def celsius_a_kelvin(celsius: float) -> float:
    if not isinstance(celsius, (int, float)):
        raise TypeError('celsius debe ser numérico')
    if celsius < -273.15:
        raise ValueError('temperatura inferior al cero absoluto')
    return float(celsius) + 273.15

def test_cero_celsius():
    assert abs(celsius_a_kelvin(0.0) - 273.15) < 1e-12

def test_cero_absoluto():
    assert abs(celsius_a_kelvin(-273.15)) < 1e-12

def test_inferior_al_limite():
    try:
        celsius_a_kelvin(-274.0)
    except ValueError:
        pass
    else:
        raise AssertionError('Se esperaba ValueError')

import math

def porcentaje_cambio(inicial: float, final: float) -> float:
    if inicial == 0:
        raise ValueError('inicial no puede ser cero')
    return 100.0 * (final - inicial) / inicial

def test_porcentaje_cambio():
    assert math.isclose(porcentaje_cambio(10, 12), 20.0)

def test_inicial_cero():
    try:
        porcentaje_cambio(0, 1)
    except ValueError:
        pass
    else:
        raise AssertionError('se esperaba ValueError')

